{/* LEVA STRANA NAVBARA */}
<div style={{ display: "flex", alignItems: "center", gap: "10px", height: "100%" }}>
  <span
    className="btnNav"
    onClick={() => navigate("/dodaj_sobu")}
    style={{ height: "40px", display: "flex", alignItems: "center", padding: "0 15px" }}
  >
    Dodaj novu sobu
  </span>

  <span
    className="btnNav"
    onClick={() => navigate("/gosti_recepcionar")}
    style={{ height: "40px", display: "flex", alignItems: "center", padding: "0 15px" }}
  >
    Gosti
  </span>

  {/* Novo dugme za Sve rezervacije */}
  <span
    className="btnNav"
    onClick={() => navigate("/sve-rezervacije")}
    style={{ height: "40px", display: "flex", alignItems: "center", padding: "0 15px" }}
  >
    Rezervacije
  </span>

  <input
    type="text"
    style={{
      width: "250px",
      height: "35px",
      fontSize: "16px",
      borderRadius: "8px",
      padding: "5px 10px",
    }}
  />
</div>
